<?php
namespace App\Domain\Characters\Data;use App\Domain\Equipment\Data\CharacterEquipmentStats;
final class CharacterStatsBreakdown{const SCHEMA_VERSION=2;private $base;private $equipment;private $effective;public function __construct(CharacterStats $base,CharacterEquipmentStats $equipment,CharacterStats $effective){$this->base=$base;$this->equipment=$equipment;$this->effective=$effective;}public function base(){return$this->base;}public function equipment(){return$this->equipment->totalBonuses();}public function equipmentBase(){return$this->equipment->baseBonuses();}public function refinement(){return$this->equipment->refinementBonuses();}public function equipmentDetails(){return$this->equipment;}public function effective(){return$this->effective;}public function equipmentSources(){return$this->equipment->sources();}public function toSnapshotArray(){return['schema_version'=>self::SCHEMA_VERSION,'base'=>$this->statsArray($this->base),'equipment'=>$this->equipment->totalBonuses()->toArray(),'equipment_base'=>$this->equipment->baseBonuses()->toArray(),'refinement'=>$this->equipment->refinementBonuses()->toArray(),'effective'=>$this->statsArray($this->effective),'equipment_sources'=>$this->equipment->sources()];}public static function supportsSnapshot(array $snapshot){return isset($snapshot['schema_version'])&&in_array((int)$snapshot['schema_version'],[1,2],true)&&isset($snapshot['base'],$snapshot['equipment'],$snapshot['effective'],$snapshot['equipment_sources']);}private function statsArray(CharacterStats $s){return['max_health'=>$s->maxHealth(),'current_health'=>$s->currentHealth(),'attack'=>$s->attack(),'defense'=>$s->defense(),'accuracy_rate'=>$s->accuracyRate(),'evasion_rate'=>$s->evasionRate(),'critical_chance'=>$s->criticalChance(),'critical_damage_multiplier'=>$s->criticalDamageMultiplier(),'attack_speed'=>$s->attackSpeed(),'damage_reduction_rate'=>$s->damageReductionRate(),'loot_bonus'=>$s->lootBonus(),'experience_bonus'=>$s->experienceBonus(),'gold_bonus'=>$s->goldBonus(),'power'=>$s->power()];}}
